type LineJointMode int //gd:Line2D.LineJointMode

const (
	// Makes the polyline's joints pointy, connecting the sides of the two segments by extending them until they intersect. If the rotation of a joint is too big (based on [SharpLimit]), the joint falls back to [LineJointBevel] to prevent very long miters.
	//
	// [SharpLimit]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SharpLimit
	LineJointSharp LineJointMode = 0
	// Makes the polyline's joints bevelled/chamfered, connecting the sides of the two segments with a simple line.
	LineJointBevel LineJointMode = 1
	// Makes the polyline's joints rounded, connecting the sides of the two segments with an arc. The detail of this arc depends on [RoundPrecision].
	//
	// [RoundPrecision]: https://pkg.go.dev/graphics.gd/classdb/#Instance.RoundPrecision
	LineJointRound LineJointMode = 2
)

type LineCapMode int //gd:Line2D.LineCapMode

const (
	// Draws no line cap.
	LineCapNone LineCapMode = 0
	// Draws the line cap as a box, slightly extending the first/last segment.
	LineCapBox LineCapMode = 1
	// Draws the line cap as a semicircle attached to the first/last segment.
	LineCapRound LineCapMode = 2
)

type LineTextureMode int //gd:Line2D.LineTextureMode

const (
	// Takes the left pixels of the texture and renders them over the whole polyline.
	LineTextureNone LineTextureMode = 0
	// Tiles the texture over the polyline. [CanvasItem.TextureRepeat] of the [Line2D] node must be [Canvasitem.TextureRepeatEnabled] or [Canvasitem.TextureRepeatMirror] for it to work properly.
	//
	// [CanvasItem.TextureRepeat]: https://pkg.go.dev/graphics.gd/classdb/CanvasItem#Instance.TextureRepeat
	// [Line2D]: https://pkg.go.dev/graphics.gd/classdb/Line2D
	LineTextureTile LineTextureMode = 1
	// Stretches the texture across the polyline. [CanvasItem.TextureRepeat] of the [Line2D] node must be [Canvasitem.TextureRepeatDisabled] for best results.
	//
	// [CanvasItem.TextureRepeat]: https://pkg.go.dev/graphics.gd/classdb/CanvasItem#Instance.TextureRepeat
	// [Line2D]: https://pkg.go.dev/graphics.gd/classdb/Line2D
	LineTextureStretch LineTextureMode = 2
)
